VALUES
  ('disabled-23e15ae5-moex-00050', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「人天生就有建築的本能。《高塔，一種□□□□的建築》一書中，描述 一個事業受挫、婚姻失敗的中年人，自己到野外湖濱建造高塔的過程。雖 然不是建築科班出身，但他受到內心本能的驅使，開始在湖邊建造一座高 塔。過程中，他感受到內心的沉澱與改變。等到高塔建造完成，他似乎得 到了某種力量，又可以重新去面對自己不完美的人生。」 根據文意，最適合填入□□□□，用以描述文中高塔特質的選項是：', '["隨心所欲", "自我療癒", "挑戰極限", "睥睨天下"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
